mapper.select:
SELECT id, provider, provider_id, email, nickname, profile_image_url, role,
       created_at, updated_at, deleted_at, suspended_from, suspended_until, demoted_at
FROM users
WHERE provider = #{provider}
  AND provider_id = #{providerId}
  AND deleted_at IS NULL

SELECT EXISTS (
    SELECT 1 FROM users
    WHERE nickname = #{nickname} AND deleted_at IS NULL

        AND id != #{excludeUserId}

)
